var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그 꿈에선 한 아이를 마주보고 있다.","JPN":"その夢では、ある子どもと向き合っていた。","ENG":"I was looking at a girl in my dream.","TWN":"在那個夢裡面對著一個孩子。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"몸에 맞지 않게 크고 화려한 옷을 입은 소녀.","JPN":"体に合わない、大きくて派手な服を着た少女。","ENG":"A girl in an extravagant dress that didn’t quite suit her.","TWN":"一個穿著過於寬鬆又華麗衣服的少女。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"잊어버려도 이상하지 않을 어린 시절의 기억이지만,","JPN":"忘れてもおかしくない幼い頃の記憶なのに、","ENG":"It was a distant memory from my childhood,","TWN":"雖然這個童年回憶不記得也很正常，"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"당장 눈앞의 일처럼 생생하다.","JPN":"昨日のことのように鮮明だ。","ENG":"but I still remember it like yesterday.","TWN":"卻是如此歷歷在目。"},"stage":{"bg":"NANAHARA_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>다시 뵐 수 있을까요?</color>","JPN":"<color=#ffd34c>またお会いできますか？</color>","ENG":"<color=#ffd34c>Will I ever see you again?</color>","TWN":"<color=#ffd34c>能再見到嗎？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"..."},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"어이! 미나토! 그쪽으로 공 날아간다!","JPN":"おーい！　湊！　そっちにボールが行ったぞ！","ENG":"Hey, Minato! Pass me the ball!","TWN":"喂！南裕夏！球往那邊去了！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BALL"},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"들었어? 오늘 학교 결석한 애들 얘기?","JPN":"あの話聞いた？　今日休んだ子たちの話。","ENG":"Did you hear about the kids who didn’t come to school today?","TWN":"聽說了嗎？那些缺席的同學？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_02"},{"id":"L23_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"맞아. 침식 재난 때문이라며. 전부 B동 쪽에 사는 애들이라더라.","JPN":"そうそう。侵食災害のせいでしょ？\\nみんなB番地のほうに住んでる子なんだって。","ENG":"I did. Because of the Corruption disaster, right? They’re all from District B.","TWN":"沒錯，聽說是因爲侵蝕災難，全部都是住在 B 棟那邊的同學。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"카와미츠도 거기 살잖아. 걔네 집이 완전히 무너져서 아예 이사해야 한대.","JPN":"川満もそこに住んでるよな。\\nあいつの家、倒壊して引っ越すことになったらしいよ。","ENG":"Kawamitsu lives there, too. His house collapsed, so he has to move.","TWN":"川瓦不是也住在那裡嗎，他們家全部倒塌了，不得不搬家了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"이럴 때 도시관리국은 뭐하나 몰라. 태스크포스만 제때 불러 주기만 해도 충분히 막을 수 있는 일인데 말이지.","JPN":"こんな時に都市管理局は何してんだろうな。\\n早くタスクフォースカンパニーを呼んでくれてたら十分防げたことだったのにさ。","ENG":"What’s City Management doing? They could have called in a TASKFORCE and prevented the whole thing.","TWN":"這時候不知道城市管理局在幹什麼。只要趕快找來特遣勢力公司，就可以阻止啦！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그러게나 말이야. 내가 카운터로 각성하면 만사 해결인데.","JPN":"そうそう。俺がカウンターに覚醒すれば万事オッケーなのにな。","ENG":"Yeah. I would have crushed them all if I was a Counter.","TWN":"可不是嗎。如果我覺醒成制裁者的話，一切就解決了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"웃기시네. 우리 같이 밋밋한 녀석들이 카운터로 각성할 리 있냐.","JPN":"冗談だろ。俺たちみたいな何の取り柄もないやつがカウンターに覚醒するわけないじゃん。","ENG":"Dream on. There’s no way people like us will become Counters. We’re too plain.","TWN":"笑死人了，像我們這種平凡無奇的傢伙，怎麼可能覺醒成制裁者？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"안 그래, 미나토?","JPN":"な？　湊。","ENG":"Don’t you agree, Minato?","TWN":"不是嗎，南裕夏？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……응?","JPN":"……うん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"하나도 안 듣고 있었구나, 너. 얘가 카운터로 각성한다고 하잖아.","JPN":"お前、全然聞いてなかったのかよ。\\nこいつがカウンターに覚醒とかありえねーって話してたろ。","ENG":"Come back down to earth, buddy. Your friend here says he wants to be a Counter.","TWN":"你都沒在聽喔？他不是說會覺醒成制裁者嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"어. 그렇지 뭐. 응원할게.","JPN":"ああ、そうか。応援するよ。","ENG":"Oh, okay. Good luck with that.","TWN":"喔，是喔，加油。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"수상한데…….","JPN":"怪しいな……","ENG":"Something's off.","TWN":"你好奇怪喔……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"무슨 소리야? 수상하다니?","JPN":"怪しいって、なにが？","ENG":"Huh? What’s off?","TWN":"什麼意思？我哪裡奇怪？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"체육 시간 때도 멍하니 있더니, 무슨 생각을 하고 있는 거야? 여자 친구?","JPN":"体育の授業中もボーっとしてたし、何考えてるんだ？\\n彼女でもできたか？","ENG":"You weren’t yourself at P.E., either. What’s wrong? You met a girl or something?","TWN":"上體育課也在發呆，你在想什麼？ 女朋友？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐, 그냥…… <color=#ffd34c>아르바이트를 하나 더 뛰어야 하나</color> 같은 생각?","JPN":"いや、まあ……<color=#ffd34c>バイト増やそうかな</color>みたいな？","ENG":"Nothing... I was just thinking whether <color=#ffd34c>I should get another side job</color>.","TWN":"喔，就是在想……<color=#ffd34c>還要再多接一個打工</color>嗎？這樣。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"아르바이트? 너네 집도 싱크홀에 휘말렸던 거야?","JPN":"バイト？　お前んちもシンクホールに巻き込まれたのか？","ENG":"A side job? You lost your home to the sinkhole too?","TWN":"打工？你家也被捲入到滲穴裡嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"에이, 얘네 집은 F동이잖아. 데이트비 때문인 게 분명해.","JPN":"いや、こいつの家はF番地だろ。デート代のために決まってるじゃん。","ENG":"No, he lives in District F. He’s seeing a girl, I’m sure of it.","TWN":"哎唷，他們家是 F 棟欸。很明顯是要賺約會基金啦。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아니라니까.","JPN":"違うって。","ENG":"I told you, I’m not.","TWN":"都說不是了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"생활비가 빠듯해서 그래. 할아버지 요양원비가 또 올랐거든.","JPN":"生活費がぎりぎりでさ。じいちゃんの老人ホームの月額がまた上がったんだ。","ENG":"It’s just that I need more money to pay my grandpa’s medical expenses.","TWN":"是因爲生活費吃緊。爺爺療養院的費用又漲了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"喔。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"그…… 미안.","JPN":"えっと……ごめん。","ENG":"Um... Sorry.","TWN":"那個…… 抱歉。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"쓸데없는 소리 좀 하지 마, 바보야.","JPN":"くだらないこと言うなよ、バカ。","ENG":"Watch your mouth, you idiot.","TWN":"道歉有用嗎，傻瓜。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"뭐래. 네가 더 바보거든?","JPN":"は？　お前のほうがバカだろ！","ENG":"You’re the idiot, idiot.","TWN":"說什麼呢，你才是傻瓜咧！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아하하……. 난 됐으니까 싸우지 마.","JPN":"あはは……僕は平気だからケンカするなよ。","ENG":"Hah hah... I’m fine, guys. Chill out.","TWN":"哀哀……我沒事啦，你們不要吵架。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"하하하! 여기에 있는 걸 알고 왔다! 미나토!","JPN":"ハハハ！　ここにいるのはわかってるぞ、湊！","ENG":"Hah hah hah! I know you’re here, Minato!","TWN":"哈哈哈！我就知道你在這裡！南裕夏！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SLIDE"},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"우왓, 저 흑염룡 녀석 또 왔네.","JPN":"ゲッ、あの中二病のやつ、また来たか。","ENG":"Oh, the Dark Flame Dragon is here for you again.","TWN":"哇喔，黑炎龍那傢伙又來了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"누가 보면 우리 반 애인 줄 알겠어.","JPN":"傍から見たらうちのクラスメイトと勘違いされそうだな。","ENG":"Someone might almost think that he’s from our class.","TWN":"還以爲是我們班的同學呢。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"오늘도 평범한 녀석들이랑 대화하고 있는 거냐, 미나토?","JPN":"今日も平凡なやつらと戯れてるのか、湊？","ENG":"You’re hanging out with ordinary people again, Minato?","TWN":"今天也在跟平凡的傢伙們講話喔，南裕夏？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"너란 녀석은 정말이지 심심한 생활을 좋아하는구만.","JPN":"お前ってやつは本当に退屈な生活が好きなんだな。","ENG":"You really do love a boring life, don’t you?","TWN":"你這傢伙真的很喜歡這種無聊的生活呢。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"쓸데없는 소리 좀 하지 마, 바보야.","JPN":"くだらないこと言うなよ、バカ。","ENG":"Watch your mouth, you idiot.","TWN":"說這些要幹嘛，傻瓜。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"바보라니?","JPN":"バカだと！？","ENG":"Did you just call me an idiot?","TWN":"你叫我傻瓜？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이 몸은 바보가 아니라 어둠의 결사! 오오가미 흑막조의 조장! 오오가미 마사키 님이시다!","JPN":"オレ様はバカではなく、闇の結社！　大神黒幕組の組長！\\n大神雅紀様だ！","ENG":"I’m not an idiot, but the hidden veil of darkness! The Ogami's Shadow Group’s boss! Ogami Masaki!","TWN":"我才不是傻瓜，我可是黑暗社團！大神黑幕組的組長！大神雅紀！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"흑막조라고 해 봤자 너 혼자 소꿉놀이 하고 있을 뿐이잖아.","JPN":"黒幕組って言っても、お前一人しかいないだろ？","ENG":"A group with a single member. You.","TWN":"說好聽是黑幕組，其實不過就是你一個人的辦家家酒而已。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"명예 흑막조원인 널 합쳐서 두 명이지. 예컨대 소수 정예란 뜻이다.","JPN":"名誉黒幕組のお前を入れて二人だ。つまり少数精鋭ってことだぜ。","ENG":"It’s two—including you, the honorary member. Because we only choose the elites.","TWN":"加上你這位黑幕組的榮譽組員，總共兩個人喔！也就是說，少數菁英的意思。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"들어갈 생각 없다니까…….","JPN":"だから入ったつもりはないって……","ENG":"I already told you that I don’t want to join...","TWN":"我沒有想要加入……"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그래서, 오늘은 무슨 일인데?","JPN":"で、今日はどうしたんだ？","ENG":"Anyway, what’s up?","TWN":"所以呢，今天又有什麼事？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"네가 가지고 있는 그 고대의 진실을 기록한 비문!","JPN":"お前が持ってる古代の真実を記録した碑文！","ENG":"Epitaph of the ancient truth!","TWN":"你的那個紀錄古代事蹟的碑文！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"옛 땅의 비밀을 품은 수수께끼의 유산에 대한 기록을 내게 공유해 줬으면 한다!","JPN":"古の土地の秘密を抱いた、謎の遺産に関する記録を\\nオレ様に共有してほしい！","ENG":"I want you to share the mysterious legacy of the old land!","TWN":"有關遺跡之謎的紀錄可以分享一下嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"역사 수업 과제 말이지?","JPN":"歴史の授業の宿題のことか。","ENG":"You want my history assignment?","TWN":"歷史課的功課喔？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"자, 빌려 줄 테니까 수업 시작 전에만 돌려 줘.","JPN":"ほら、貸してやるから授業の前には返せよ。","ENG":"Here you go. Just make sure to bring it back before history class starts.","TWN":"好，我借給你，上課前要還給我喔。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하하, 훌륭하군! 역시 명예 흑막조원다운 준비성이다!","JPN":"ハハハ、素晴らしい！　さすが名誉黒幕組員だ！","ENG":"Hah hah, excellent! I was wise to recruit you as an honorary member!","TWN":"哈哈，真棒！ 不愧是黑幕組的榮譽組員，凡事都有預備！"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_A_NULL","text":{"KOREA":"용케 저걸 알아듣는단 말이야.","JPN":"よくあれが理解できるな。","ENG":"I don’t understand how he understands that weird metaphor.","TWN":"你竟然聽得懂他在說什麼。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STUDENT_EXTRA_B_NULL","text":{"KOREA":"뭐, 어릴 때부터 알고 지낸 사이라잖아.","JPN":"まあ、お前たち幼馴染だもんな。","ENG":"They’ve been friends since they were children, that’s why.","TWN":"很正常吧？他們不是從小就認識嗎？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아, 그러고 보니 깜빡할 뻔했군.","JPN":"ああ、そういえば忘れるところだった。","ENG":"Oh, I almost forgot.","TWN":"對了，我差點忘了。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"궁도부 부장의 전언이다. 너와 담화를 나누고 싶다더군.","JPN":"弓道部の部長から伝言だ。お前と言葉を交わしたいらしい。","ENG":"The captain of the Archery Club sent a message for you. She wants to talk to you.","TWN":"是弓道部社長要我傳話，她想找你聊聊。"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"부장이……?","JPN":"部長が……？","ENG":"The captain?","TWN":"社長……？"},"stage":{"bg":"CLASS","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"왔구나, 나유카.","JPN":"来てくれたんだね、奈由香。","ENG":"There you are, Nayuka.","TWN":"你來啦，南裕夏。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……이로하.","JPN":"……いろは。","ENG":"Iroha.","TWN":"……伊呂波。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"얘기 들었어. 남자애들이 공 좀 차 달랬더니 그대로 골을 넣었다며?","JPN":"話は聞いたわ。ボールを蹴って渡してほしいって言われて、\\nそのままゴールを決めたって？","ENG":"I heard that you scored a goal when boys just asked you to pass the ball.","TWN":"我聽說了。男生們請你把球踢過去，結果你直接踢進球門嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그것도 반대편 골대에서.","JPN":"しかも反対側のゴールポストから。","ENG":"From the opposite end of the field.","TWN":"而且是對方的球門。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"애들끼리 축구할 때는 헛발질만 하던 애가 언제 그런 우수한 축구 인재가 됐대?","JPN":"昔はサッカーで空振りばかりしてた子が、\\nいつからそんな優秀なサッカー選手になったの？","ENG":"Since when did you become a world class soccer player? You always missed your kicks before.","TWN":"每次小朋友在踢球的時候，總是踢空的人，什麼時候變成這麼優秀的足球人才啦？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Um...","TWN":"那是……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"어쩌다 잘 찬 거지. 그냥 우연이야.","JPN":"たまたまだよ。ただの偶然さ。","ENG":"It just happened. A coincidence.","TWN":"我也不知道，只是湊巧的而已。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그럼 궁도부가 싫어진 것도 우연이야?","JPN":"じゃあ、弓道部が嫌いになったのも偶然？","ENG":"Is it also a coincidence that you don’t like the Archery Club anymore?","TWN":"那你也只是湊巧討厭弓道部嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"오해야, 이로하. 내가 궁도부를 싫어할 이유 같은 게 있을 리 없잖아.","JPN":"誤解だよ、いろは。\\n僕に弓道部が嫌いになる理由なんかあるわけないだろ。","ENG":"That’s not true, Iroha. Why would I not like it?","TWN":"這是誤會，伊呂波。我沒有理由討厭弓道部吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그럼 왜 전국대회를 코앞에 두고 갑자기 관두기로 한 건데?","JPN":"じゃあ、なんで全国大会を目前にして急に辞めたの？","ENG":"Then why did you quit right before the national competition?","TWN":"那爲什麼在全國比賽前突然說要放棄呢？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"……이건?","JPN":"……何の音？","ENG":"Huh?","TWN":"……這是？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"침식사태 경보야. 어서 대피소로 가자.","JPN":"侵食事態警報だ。急いで避難所に行こう。","ENG":"It’s the Corruption alarm. We have to go to the shelter.","TWN":"侵蝕事件警報，快去避難所吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"잠깐! 나유카, 너 언제나 그런 식으로 얼버무리잖아! 기다려!","JPN":"待ってよ！　奈由香、あんたいつもそうやって誤魔化してるじゃない！\\n待ってってば！","ENG":"Wait, Nayuka! You’re not answering my questions again! Wait!","TWN":"等一下！南裕夏，你總是用這種方式含糊帶過！ 等等我！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};